package com.google.gson;
import com.google.gson.internal.NonNullElementWrapperList;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;
import java.util.Iterator;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class JsonArrayTest {

  private JsonArray jsonArray;
  private JsonElement singleElementMock;

  @BeforeEach
  public void setUp() {
    jsonArray = new JsonArray();
    singleElementMock = mock(JsonElement.class);
  }

  @Test
  public void testGetAsCharacter_delegatesToSingleElement() {
    // Use reflection to set the private field 'elements' with a single mocked element
    try {
      // Add mock element to jsonArray
      jsonArray.add(singleElementMock);

      // Mock getAsSingleElement() via reflection to return the mocked element
      Method getAsSingleElementMethod = JsonArray.class.getDeclaredMethod("getAsSingleElement");
      getAsSingleElementMethod.setAccessible(true);

      // Spy on jsonArray to mock private method getAsSingleElement
      JsonArray spyJsonArray = Mockito.spy(jsonArray);
      doReturn(singleElementMock).when(spyJsonArray).getAsSingleElement();

      // Define behavior of singleElementMock.getAsCharacter()
      when(singleElementMock.getAsCharacter()).thenReturn('x');

      // Call the focal method
      char result = spyJsonArray.getAsCharacter();

      // Verify delegation and result
      verify(singleElementMock).getAsCharacter();
      assertEquals('x', result);

    } catch (Exception e) {
      fail("Reflection or mocking failed: " + e.getMessage());
    }
  }

  @Test
  public void testGetAsCharacter_whenEmpty_throwsIndexOutOfBoundsException() throws Exception {
    // jsonArray is empty, so getAsSingleElement() should throw IndexOutOfBoundsException
    JsonArray spyJsonArray = Mockito.spy(jsonArray);

    // Use reflection to invoke private method getAsSingleElement which throws if empty
    Method getAsSingleElementMethod = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElementMethod.setAccessible(true);

    // Confirm getAsSingleElement throws when empty
    assertThrows(IndexOutOfBoundsException.class, () -> {
      getAsSingleElementMethod.invoke(spyJsonArray);
    });

    // Because getAsCharacter calls getAsSingleElement, it should also throw IndexOutOfBoundsException
    assertThrows(IndexOutOfBoundsException.class, () -> {
      spyJsonArray.getAsCharacter();
    });
  }
}
